#include <iostream>
using namespace std;

class Box {
private:
 int length;

public:
 Box(int l) : length(l) {}

 // Friend function declaration
 friend void displayLength(Box b);
};

// Friend function definition (not a member)
void displayLength(Box b) {
 // Can access private member directly
 cout << "Length: " << b.length << endl;
}

int main() {
 Box b1(10);
 displayLength(b1); // Called like normal function
 return 0;
}

#include <iostream>
using namespace std;

class Complex {
private:
 int real, imag;

public:
 Complex(int r = 0, int i = 0) : real(r), imag(i) {}

 // Friend function for + operator
 friend Complex operator+(Complex c1, Complex c2);

 void display() {
 cout << real << " + " << imag << "i" << endl;
 }
};

// Overloaded + operator as friend
Complex operator+(Complex c1, Complex c2) {
 Complex result;
 result.real = c1.real + c2.real;
 result.imag = c1.imag + c2.imag;
 return result;
}

int main() {
 Complex c1(3, 4), c2(1, 2);
 Complex c3 = c1 + c2; // Natural syntax
 c3.display();
 return 0;
}

#include <iostream>
using namespace std;

class Point {
private:
 int x, y;

public:
 Point(int a = 0, int b = 0) : x(a), y(b) {}

 // Friend declaration for stream insertion
 friend ostream& operator<<(ostream& output, const Point& p);
};

// Overloaded << operator
ostream& operator<<(ostream& output, const Point& p) {
 output << "(" << p.x << ", " << p.y << ")";
 return output; // Enables chaining
}

int main() {
 Point p1(5, 3), p2(10, 20);
 cout << "Point 1: " << p1 << endl;
 cout << "Point 2: " << p2 << endl;
 return 0;
}

#include <iostream>
using namespace std;

class Engine {
private:
 int horsepower;
 string type;

public:
 Engine(int hp, string t) : horsepower(hp), type(t) {}

 // Grant friendship to Car class
 friend class Car;
};

class Car {
private:
 string model;
 Engine e;

public:
 Car(string m, int hp, string t) : model(m), e(hp, t) {}

 void showDetails() {
 // Can access Engine's private members
 cout << "Model: " << model << endl;
 cout << "HP: " << e.horsepower << endl;
 cout << "Engine Type: " << e.type << endl;
 }
};

int main() {
 Car c("Tesla", 500, "Electric");
 c.showDetails();
 return 0;
}

#include <iostream>
using namespace std;

class A {
private:
 int data = 100;

public:
 friend class B; // B is friend of A
};

class B {
public:
 void accessA(A& obj) {
 cout << "B can access A's data: " << obj.data << endl;
 }
};

class C : public B {
public:
 void accessA(A& obj) {
 // Cannot access - friendship not inherited
 // obj.data would cause error
 cout << "C cannot access A's data (friendship not inherited)" << endl;
 }
};

int main() {
 A a;
 B b;
 C c;

 cout << "--- Testing Inheritance of Friendship ---" << endl;
 b.accessA(a); // Works - B is friend of A
 c.accessA(a); // Doesn't work - C inherits from B but not friend

 return 0;
}
